public enum Status
{
    Open,
    InProgress,
    Closed
}

public interface IDefect
{
    int Id { get; set; }
    string Description { get; set; }
    Status Status { get; set; }
}

public class Defect : IDefect
{
    public int Id { get; set; }
    public string Description { get; set; }
    public Status Status { get; set; }
}

public class DefectRepository
{
    private readonly string _connectionString;

    public DefectRepository(string connectionString)
    {
        _connectionString = connectionString;
    }

    public void InsertDefect(Defect defect)
    {
        using (SqlConnection connection = new SqlConnection(_connectionString))
        {
            connection.Open();

            string query = "INSERT INTO Defects (Id, Description, Status) VALUES (@Id, @Description, @Status)";
            SqlCommand command = new SqlCommand(query, connection);

            command.Parameters.AddWithValue("@Id", defect.Id);
            command.Parameters.AddWithValue("@Description", defect.Description);
            command.Parameters.AddWithValue("@Status", (int)defect.Status);

            command.ExecuteNonQuery();
        }
    }

    public Defect RetrieveDefect(int id)
    {
        using (SqlConnection connection = new SqlConnection(_connectionString))
        {
            connection.Open();

            string query = "SELECT Id, Description, Status FROM Defects WHERE Id = @Id";
            SqlCommand command = new SqlCommand(query, connection);

            command.Parameters.AddWithValue("@Id", id);

            SqlDataReader reader = command.ExecuteReader();

            if (reader.Read())
            {
                Defect defect = new Defect
                {
                    Id = reader.GetInt32(0),
                    Description = reader.GetString(1),
                    Status = (Status)reader.GetInt32(2)
                };

                return defect;
            }

            return null;
        }
    }
}

public class DefectValidator
{
    public void Validate(Defect defect)
    {
        if (!Enum.IsDefined(typeof(Status), defect.Status))
        {
            throw new ArgumentException("Invalid status", nameof(defect.Status));
        }
    }
}
```

