    {
        Username = username;
        Password = password;
    }

    public abstract void ValidateCredentials(string username, string password);
}

// Subclass for administrators
public class Administrator : User
{
    public string Role { get; set; }

    public Administrator(string username, string password, string role) 
        : base(username, password)
    {
        Role = role;
    }

    public override void ValidateCredentials(string username, string password)
    {
        // Validate administrator credentials using SQL database
        using (SqlConnection connection = new SqlConnection("Data Source=<database_server>;Initial Catalog=<database_name>;Integrated Security=True"))
        {
            connection.Open();
            SqlCommand command = new SqlCommand("SELECT * FROM Administrators WHERE Username = @username AND Password = @password", connection);
            command.Parameters.AddWithValue("@username", username);
            command.Parameters.AddWithValue("@password", password);
            SqlDataReader reader = command.ExecuteReader();
            if (reader.Read())
            {
                // Credentials are valid
                Console.WriteLine("Administrator credentials are valid.");
            }
            else
            {
                // Credentials are invalid
                Console.WriteLine("Administrator credentials are invalid.");
            }
        }
    }
}

